3816 /// Reorders the given \p Reuses mask according to the given \p Mask. \p Reuses
3817 /// contains original mask for the scalars reused in the node. Procedure
3818 /// transform this mask in accordance with the given \p Mask.
3819 static void reorderReuses(SmallVectorImpl<int> &Reuses, ArrayRef<int> Mask) {
3820   assert(!Mask.empty() && Reuses.size() == Mask.size() &&
3821          "Expected non-empty mask.");
3822   SmallVector<int> Prev(Reuses.begin(), Reuses.end());
3823   Prev.swap(Reuses);
3824   for (unsigned I = 0, E = Prev.size(); I < E; ++I)
3825     if (Mask[I] != PoisonMaskElem)
3826       Reuses[Mask[I]] = Prev[I];
3827 }
3828 
3829 /// Reorders the given \p Order according to the given \p Mask. \p Order - is
3830 /// the original order of the scalars. Procedure transforms the provided order
3831 /// in accordance with the given \p Mask. If the resulting \p Order is just an
3832 /// identity order, \p Order is cleared.
3833 static void reorderOrder(SmallVectorImpl<unsigned> &Order, ArrayRef<int> Mask,
3834                          bool BottomOrder = false) {
3835   assert(!Mask.empty() && "Expected non-empty mask.");
3836   unsigned Sz = Mask.size();
3837   if (BottomOrder) {
3838     SmallVector<unsigned> PrevOrder;
3839     if (Order.empty()) {
3840       PrevOrder.resize(Sz);
3841       std::iota(PrevOrder.begin(), PrevOrder.end(), 0);
3842     } else {
3843       PrevOrder.swap(Order);
3844     }
3845     Order.assign(Sz, Sz);
3846     for (unsigned I = 0; I < Sz; ++I)
3847       if (Mask[I] != PoisonMaskElem)
3848         Order[I] = PrevOrder[Mask[I]];
3849     if (all_of(enumerate(Order), [&](const auto &Data) {
3850           return Data.value() == Sz || Data.index() == Data.value();
3851         })) {
3852       Order.clear();
3853       return;
3854     }
3855     fixupOrderingIndices(Order);
3856     return;
3857   }
3858   SmallVector<int> MaskOrder;
3859   if (Order.empty()) {
3860     MaskOrder.resize(Sz);
3861     std::iota(MaskOrder.begin(), MaskOrder.end(), 0);
3862   } else {
3863     inversePermutation(Order, MaskOrder);
3864   }
3865   reorderReuses(MaskOrder, Mask);
3866   if (ShuffleVectorInst::isIdentityMask(MaskOrder, Sz)) {
3867     Order.clear();
3868     return;
3869   }
3870   Order.assign(Sz, Sz);
3871   for (unsigned I = 0; I < Sz; ++I)
3872     if (MaskOrder[I] != PoisonMaskElem)
3873       Order[MaskOrder[I]] = I;
3874   fixupOrderingIndices(Order);
3875 }
