14309   case Instruction::PHI: {
14310     PHINode *PN = cast<PHINode>(I);
14311     SmallVector<Value *> Ops(PN->incoming_values().begin(),
14312                              PN->incoming_values().end());
14313     return TryProcessInstruction(I, *ITE, BitWidth, Ops);
14314   }
14315 
14316   // Otherwise, conservatively give up.
14317   default:
14318     break;
14319   }
14320   MaxDepthLevel = 1;
14321   return FinalAnalysis();
14322 }
14323 
14324 void BoUpSLP::computeMinimumValueSizes() {
14325   // We only attempt to truncate integer expressions.
14326   bool IsStoreOrInsertElt =
14327       VectorizableTree.front()->getOpcode() == Instruction::Store ||
14328       VectorizableTree.front()->getOpcode() == Instruction::InsertElement;
14329   if ((IsStoreOrInsertElt || UserIgnoreList) &&
14330       ExtraBitWidthNodes.size() <= 1 &&
14331       (!CastMaxMinBWSizes || CastMaxMinBWSizes->second == 0 ||
14332        CastMaxMinBWSizes->first / CastMaxMinBWSizes->second <= 2))
14333     return;
14334 
14335   unsigned NodeIdx = 0;
14336   if (IsStoreOrInsertElt &&
14337       VectorizableTree.front()->State != TreeEntry::NeedToGather)
14338     NodeIdx = 1;
14339 
14340   // Ensure the roots of the vectorizable tree don't form a cycle.
14341   if (VectorizableTree[NodeIdx]->State == TreeEntry::NeedToGather ||
14342       (NodeIdx == 0 && !VectorizableTree[NodeIdx]->UserTreeIndices.empty()) ||
14343       (NodeIdx != 0 && any_of(VectorizableTree[NodeIdx]->UserTreeIndices,
14344                               [NodeIdx](const EdgeInfo &EI) {
14345                                 return EI.UserTE->Idx >
14346                                        static_cast<int>(NodeIdx);
14347                               })))
14348     return;
14349 
14350   // The first value node for store/insertelement is sext/zext/trunc? Skip it,
14351   // resize to the final type.
14352   bool IsTruncRoot = false;
14353   bool IsProfitableToDemoteRoot = !IsStoreOrInsertElt;
14354   SmallVector<unsigned> RootDemotes;
14355   if (NodeIdx != 0 &&
14356       VectorizableTree[NodeIdx]->State == TreeEntry::Vectorize &&
14357       VectorizableTree[NodeIdx]->getOpcode() == Instruction::Trunc) {
14358     assert(IsStoreOrInsertElt && "Expected store/insertelement seeded graph.");
14359     IsTruncRoot = true;
14360     RootDemotes.push_back(NodeIdx);
14361     IsProfitableToDemoteRoot = true;
14362     ++NodeIdx;
14363   }
14364 
14365   // Analyzed in reduction already and not profitable - exit.
14366   if (AnalyzedMinBWVals.contains(VectorizableTree[NodeIdx]->Scalars.front()))
14367     return;
14368 
14369   SmallVector<Value *> ToDemote;
14370   DenseMap<Instruction *, SmallVector<unsigned>> DemotedConsts;
14371   auto ComputeMaxBitWidth = [&](ArrayRef<Value *> TreeRoot, unsigned VF,
14372                                 bool IsTopRoot, bool IsProfitableToDemoteRoot,
14373                                 unsigned Opcode, unsigned Limit,
14374                                 bool IsTruncRoot) {
14375     ToDemote.clear();
14376     auto *TreeRootIT = dyn_cast<IntegerType>(TreeRoot[0]->getType());
14377     if (!TreeRootIT || !Opcode)
14378       return 0u;
14379 
14380     if (AnalyzedMinBWVals.contains(TreeRoot.front()))
14381       return 0u;
14382 
14383     unsigned NumParts = TTI->getNumberOfParts(
14384         FixedVectorType::get(TreeRoot.front()->getType(), VF));
14385 
14386     // The maximum bit width required to represent all the values that can be
14387     // demoted without loss of precision. It would be safe to truncate the roots
14388     // of the expression to this width.
14389     unsigned MaxBitWidth = 1u;
14390 
14391     // True if the roots can be zero-extended back to their original type,
14392     // rather than sign-extended. We know that if the leading bits are not
14393     // demanded, we can safely zero-extend. So we initialize IsKnownPositive to
14394     // True.
14395     // Determine if the sign bit of all the roots is known to be zero. If not,
14396     // IsKnownPositive is set to False.
14397     bool IsKnownPositive = all_of(TreeRoot, [&](Value *R) {
14398       KnownBits Known = computeKnownBits(R, *DL);
14399       return Known.isNonNegative();
14400     });
14401 
14402     // We first check if all the bits of the roots are demanded. If they're not,
14403     // we can truncate the roots to this narrower type.
14404     for (auto *Root : TreeRoot) {
14405       unsigned NumSignBits = ComputeNumSignBits(Root, *DL, 0, AC, nullptr, DT);
14406       TypeSize NumTypeBits = DL->getTypeSizeInBits(Root->getType());
14407       unsigned BitWidth1 = NumTypeBits - NumSignBits;
14408       // If we can't prove that the sign bit is zero, we must add one to the
14409       // maximum bit width to account for the unknown sign bit. This preserves
14410       // the existing sign bit so we can safely sign-extend the root back to the
14411       // original type. Otherwise, if we know the sign bit is zero, we will
14412       // zero-extend the root instead.
14413       //
14414       // FIXME: This is somewhat suboptimal, as there will be cases where adding
14415       //        one to the maximum bit width will yield a larger-than-necessary
14416       //        type. In general, we need to add an extra bit only if we can't
14417       //        prove that the upper bit of the original type is equal to the
14418       //        upper bit of the proposed smaller type. If these two bits are
14419       //        the same (either zero or one) we know that sign-extending from
14420       //        the smaller type will result in the same value. Here, since we
14421       //        can't yet prove this, we are just making the proposed smaller
14422       //        type larger to ensure correctness.
14423       if (!IsKnownPositive)
14424         ++BitWidth1;
14425 
14426       APInt Mask = DB->getDemandedBits(cast<Instruction>(Root));
14427       unsigned BitWidth2 = Mask.getBitWidth() - Mask.countl_zero();
14428       MaxBitWidth =
14429           std::max<unsigned>(std::min(BitWidth1, BitWidth2), MaxBitWidth);
14430     }
14431 
14432     if (MaxBitWidth < 8 && MaxBitWidth > 1)
14433       MaxBitWidth = 8;
14434 
14435     // If the original type is large, but reduced type does not improve the reg
14436     // use - ignore it.
14437     if (NumParts > 1 &&
14438         NumParts ==
14439             TTI->getNumberOfParts(FixedVectorType::get(
14440                 IntegerType::get(F->getContext(), bit_ceil(MaxBitWidth)), VF)))
14441       return 0u;
14442 
14443     bool IsProfitableToDemote = Opcode == Instruction::Trunc ||
14444                                 Opcode == Instruction::SExt ||
14445                                 Opcode == Instruction::ZExt || NumParts > 1;
14446     // Conservatively determine if we can actually truncate the roots of the
14447     // expression. Collect the values that can be demoted in ToDemote and
14448     // additional roots that require investigating in Roots.
14449     for (auto *Root : TreeRoot) {
14450       DenseSet<Value *> Visited;
14451       unsigned MaxDepthLevel = IsTruncRoot ? Limit : 1;
14452       bool NeedToDemote = IsProfitableToDemote;
14453 
14454       if (!collectValuesToDemote(Root, IsProfitableToDemoteRoot, MaxBitWidth,
14455                                  ToDemote, DemotedConsts, Visited,
14456                                  MaxDepthLevel, NeedToDemote, IsTruncRoot) ||
14457           (MaxDepthLevel <= Limit &&
14458            !(((Opcode == Instruction::SExt || Opcode == Instruction::ZExt) &&
14459               (!IsTopRoot || !(IsStoreOrInsertElt || UserIgnoreList) ||
14460                DL->getTypeSizeInBits(Root->getType()) /
14461                        DL->getTypeSizeInBits(
14462                            cast<Instruction>(Root)->getOperand(0)->getType()) >
14463                    2)))))
14464         return 0u;
14465     }
14466     // Round MaxBitWidth up to the next power-of-two.
14467     MaxBitWidth = bit_ceil(MaxBitWidth);
14468 
14469     return MaxBitWidth;
14470   };
14471 
14472   // If we can truncate the root, we must collect additional values that might
14473   // be demoted as a result. That is, those seeded by truncations we will
14474   // modify.
14475   // Add reduction ops sizes, if any.
14476   if (UserIgnoreList &&
14477       isa<IntegerType>(VectorizableTree.front()->Scalars.front()->getType())) {
14478     for (Value *V : *UserIgnoreList) {
14479       auto NumSignBits = ComputeNumSignBits(V, *DL, 0, AC, nullptr, DT);
14480       auto NumTypeBits = DL->getTypeSizeInBits(V->getType());
14481       unsigned BitWidth1 = NumTypeBits - NumSignBits;
14482       if (!isKnownNonNegative(V, SimplifyQuery(*DL)))
14483         ++BitWidth1;
14484       auto Mask = DB->getDemandedBits(cast<Instruction>(V));
14485       unsigned BitWidth2 = Mask.getBitWidth() - Mask.countl_zero();
14486       ReductionBitWidth =
14487           std::max(std::min(BitWidth1, BitWidth2), ReductionBitWidth);
14488     }
14489     if (ReductionBitWidth < 8 && ReductionBitWidth > 1)
14490       ReductionBitWidth = 8;
14491 
14492     ReductionBitWidth = bit_ceil(ReductionBitWidth);
14493   }
14494   bool IsTopRoot = NodeIdx == 0;
14495   while (NodeIdx < VectorizableTree.size() &&
14496          VectorizableTree[NodeIdx]->State == TreeEntry::Vectorize &&
14497          VectorizableTree[NodeIdx]->getOpcode() == Instruction::Trunc) {
14498     RootDemotes.push_back(NodeIdx);
14499     ++NodeIdx;
14500     IsTruncRoot = true;
14501   }
14502   while (NodeIdx < VectorizableTree.size()) {
14503     ArrayRef<Value *> TreeRoot = VectorizableTree[NodeIdx]->Scalars;
14504     unsigned Limit = 2;
14505     unsigned Opcode = VectorizableTree[NodeIdx]->getOpcode();
14506     if (IsTopRoot &&
14507         ReductionBitWidth ==
14508             DL->getTypeSizeInBits(
14509                 VectorizableTree.front()->Scalars.front()->getType()))
14510       Limit = 3;
14511     unsigned MaxBitWidth = ComputeMaxBitWidth(
14512         TreeRoot, VectorizableTree[NodeIdx]->getVectorFactor(), IsTopRoot,
14513         IsProfitableToDemoteRoot, Opcode, Limit, IsTruncRoot);
14514     if (ReductionBitWidth != 0 && (IsTopRoot || !RootDemotes.empty())) {
14515       if (MaxBitWidth != 0 && ReductionBitWidth < MaxBitWidth)
14516         ReductionBitWidth = bit_ceil(MaxBitWidth);
14517       else if (MaxBitWidth == 0)
14518         ReductionBitWidth = 0;
14519     }
